   228	func generateAgenticAssessmentFindings(assessments []AgenticAssessment) []Finding {
   229		findings := make([]Finding, 0, len(assessments))
   230		for _, assessment := range assessments {
   231			category := "agentic"
   232			impact := "Review recommended"
   233			switch assessment.Kind {
   234			case "resource_heavy_for_domain":
   235				category = "performance"
   236				impact = "Higher cost and latency than a comparable well-behaved run"
   237			case "overkill_for_agentic":
   238				category = "optimization"
   239				impact = "A deterministic implementation may be cheaper and easier to govern"
   240			case "poor_agentic_control":
   241				category = "agentic"
   242				impact = "Broad or weakly controlled behavior can reduce trust even when the run succeeds"
   243			case "partially_reducible":
   244				category = "optimization"
   245				impact = "Moving data-gathering turns to deterministic steps reduces inference cost"
   246			case "model_downgrade_available":
   247				category = "optimization"
   248				impact = "A smaller model could reduce per-run cost significantly for this task domain"
   249			case "delegated_context_present":
   250				category = "coordination"
   251				impact = "Context continuity improves downstream debugging and auditability"
   252			}
   253			findings = append(findings, Finding{
   254				Category:    category,
   255				Severity:    assessment.Severity,
   256				Title:       prettifyAssessmentKind(assessment.Kind),
   257				Description: assessment.Summary,
   258				Impact:      impact,
   259			})
   260		}
   261		return findings
   262	}
