   264	func generateAgenticAssessmentRecommendations(assessments []AgenticAssessment) []Recommendation {
   265		recommendations := make([]Recommendation, 0, len(assessments))
   266		for _, assessment := range assessments {
   267			if assessment.Recommendation == "" || assessment.Severity == "info" {
   268				continue
   269			}
   270			priority := "medium"
   271			if assessment.Severity == "high" {
   272				priority = "high"
   273			}
   274			recommendations = append(recommendations, Recommendation{
   275				Priority: priority,
   276				Action:   assessment.Recommendation,
   277				Reason:   assessment.Summary,
   278			})
   279		}
   280		return recommendations
   281	}
