   283	// computeAgenticFraction classifies tool sequences into reasoning vs. data-gathering
   284	// turns and returns the ratio of reasoning turns to total turns.
   285	// Reasoning turns are those where the agent makes decisions, writes output, or uses
   286	// multiple tool types. Data-gathering turns use only read-oriented tools.
   287	func computeAgenticFraction(processedRun ProcessedRun) float64 {
   288		run := processedRun.Run
   289		if run.Turns <= 0 {
   290			auditAgenticLog.Printf("Computing agentic fraction: run_id=%d turns=0, returning 0.0", processedRun.Run.DatabaseID)
   291			return 0.0
   292		}
   293		auditAgenticLog.Printf("Computing agentic fraction: run_id=%d turns=%d safe_items=%d", processedRun.Run.DatabaseID, run.Turns, run.SafeItemsCount)
   294	
   295		// If no tool sequence data, estimate from write actions
   296		writeCount := run.SafeItemsCount
   297		if writeCount > 0 && run.Turns > 0 {
   298			// At minimum, the fraction of turns that produced write actions are agentic
   299			// and non-write turns doing data gathering are deterministic-reducible
   300			agenticTurns := writeCount
   301			// Add reasoning turns: at least 1 turn of reasoning per write action,
   302			// plus initial planning turn
   303			reasoningTurns := min(writeCount+1, run.Turns)
   304			agenticTurns = max(agenticTurns, reasoningTurns)
   305			agenticTurns = min(agenticTurns, run.Turns)
   306			return float64(agenticTurns) / float64(run.Turns)
   307		}
   308	
   309		// No write actions: if the run is read-only with few turns, nearly all
   310		// turns are reasoning (the AI is analyzing, not just gathering data)
   311		if run.Turns <= 3 {
   312			return 1.0
   313		}
   314	
   315		// For longer read-only runs, assume early turns gather context and
   316		// later turns do analysis. Heuristic: half the turns are reasoning.
   317		return 0.5
   318	}
