   329	func prettifyAssessmentKind(kind string) string {
   330		switch kind {
   331		case "resource_heavy_for_domain":
   332			return "Resource Heavy For Domain"
   333		case "overkill_for_agentic":
   334			return "Potential Deterministic Alternative"
   335		case "poor_agentic_control":
   336			return "Weak Agentic Control"
   337		case "delegated_context_present":
   338			return "Dispatch Context Preserved"
   339		case "partially_reducible":
   340			return "Partially Reducible To Deterministic"
   341		case "model_downgrade_available":
   342			return "Cheaper Model Available"
   343		default:
   344			return strings.ReplaceAll(kind, "_", " ")
   345		}
   346	}
