    32	// isValidToolName checks if a tool name appears to be valid.
    33	// Filters out single words, common words, and other garbage that shouldn't be tools.
    34	func isValidToolName(toolName string) bool {
    35		name := strings.TrimSpace(toolName)
    36	
    37		// Filter out empty names
    38		if name == "" || name == "-" {
    39			return false
    40		}
    41	
    42		// Filter out single character names
    43		if len(name) == 1 {
    44			return false
    45		}
    46	
    47		// Filter out common English words that are likely from error messages
    48		if toolNameStopWords[name] {
    49			return false
    50		}
    51	
    52		// Tool names should typically contain underscores, hyphens, or be camelCase
    53		// or be all lowercase. Single words without these patterns are suspect.
    54		hasUnderscore := strings.Contains(name, "_")
    55		hasHyphen := strings.Contains(name, "-")
    56		hasCapital := strings.ToLower(name) != name
    57	
    58		// Reject short, all-lowercase, single-word names with no separators — these
    59		// are almost certainly log-message fragments rather than real tool names.
    60		words := strings.Fields(name)
