   334	// extractToolCallSizes extracts tool call input and output sizes from Copilot JSON responses
   335	func (e *CopilotEngine) extractToolCallSizes(jsonStr string, toolCallMap map[string]*ToolCallInfo, verbose bool) {
   336		// Try to parse the JSON string
   337		var data map[string]any
   338		if err := json.Unmarshal([]byte(jsonStr), &data); err != nil {
   339			if verbose {
   340				copilotLogsLog.Printf("Failed to parse JSON for tool size extraction: %v", err)
   341			}
   342			return
   343		}
   344	
   345		// Look for tool_calls in the choices array (Copilot/OpenAI format)
   346		if choices, ok := data["choices"].([]any); ok {
   347			for _, choice := range choices {
   348				if choiceMap, ok := choice.(map[string]any); ok {
   349					if message, ok := choiceMap["message"].(map[string]any); ok {
   350						if toolCalls, ok := message["tool_calls"].([]any); ok {
   351							e.processToolCalls(toolCalls, toolCallMap, verbose)
   352						}
   353					}
   354				}
   355			}
   356		}
   357	
   358		// Also check for tool_calls directly in the message (alternative format)
   359		if message, ok := data["message"].(map[string]any); ok {
   360			if toolCalls, ok := message["tool_calls"].([]any); ok {
   361				e.processToolCalls(toolCalls, toolCallMap, verbose)
   362			}
   363		}
   364	}
   365	
   366	// processToolCalls processes tool_calls array and updates tool call map with sizes
   367	func (e *CopilotEngine) processToolCalls(toolCalls []any, toolCallMap map[string]*ToolCallInfo, verbose bool) {
   368		for _, toolCall := range toolCalls {
   369			if tcMap, ok := toolCall.(map[string]any); ok {
   370				// Extract function information
   371				if function, ok := tcMap["function"].(map[string]any); ok {
   372					if toolName, ok := function["name"].(string); ok {
   373						// Calculate input size from arguments (if present)
   374						inputSize := 0
   375						if arguments, ok := function["arguments"].(string); ok {
   376							inputSize = len(arguments)
   377						}
   378	
   379						// Initialize or update tool call info
   380						if toolInfo, exists := toolCallMap[toolName]; exists {
   381							toolInfo.CallCount++
   382							// Update max input size if this call is larger
   383							if inputSize > toolInfo.MaxInputSize {
   384								toolInfo.MaxInputSize = inputSize
   385								if verbose {
   386									copilotLogsLog.Printf("Updated %s MaxInputSize to %d bytes", toolName, inputSize)
   387								}
   388							}
   389						} else {
   390							toolCallMap[toolName] = &ToolCallInfo{
   391								Name:          toolName,
   392								CallCount:     1,
   393								MaxInputSize:  inputSize,
   394								MaxOutputSize: 0, // Output size extraction not yet available in Copilot logs
   395							}
   396							if verbose {
   397								copilotLogsLog.Printf("Created tool info for %s with MaxInputSize=%d bytes", toolName, inputSize)
   398							}
   399						}
   400					}
   401				}
   402			}
   403		}
   404	}
